using ModelContextProtocol;
using System.ComponentModel;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithTools<EchoTools>()
    .WithResources<ConfigResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

[McpServerToolType]
public sealed class EchoTools
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public string Echo([Description("The message to echo")] string message)
        => $"Echo: {message}";

    [McpServerTool, Description("Returns the current server UTC time.")]
    public string GetServerTime()
        => $"Server time: {DateTime.UtcNow:O}";
}

[McpServerResourceType]
public sealed class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "AppSettings",
        Description = "Returns the current application configuration.",
        MimeType = "application/json")]
    public string GetAppSettings()
        => """
        {
            "environment": "production",
            "version": "1.0.0",
            "features": {
                "caching": true,
                "rateLimit": 100
            }
        }
        """;

    [McpServerResource(
        UriTemplate = "config://app/features/{featureName}",
        Name = "FeatureFlag",
        Description = "Returns the status of a specific feature flag.",
        MimeType = "application/json")]
    public string GetFeatureFlag(string featureName)
        => $$"""
        {
            "feature": "{{featureName}}",
            "enabled": true
        }
        """;
}

